import sys
from typing import List

class Solution:
  def greedyCoinChange(self, coins: List[int], amount: int) -> int:
    coins.sort(reverse=True)
    count = 0
    for coin in coins:
      while amount >= coin and amount > 0:
        amount -= coin
        count++
      if amount == 0:
        break
    return count

if __name__ == '__main__':
